CREATE TABLE IF NOT EXISTS users (id BINARY(16) NOT NULL PRIMARY KEY, email VARCHAR(255) NOT NULL, "name" VARCHAR(255) NOT NULL, password_hash VARCHAR(255) NOT NULL);
CREATE UNIQUE INDEX IF NOT EXISTS users_email ON users (email);
CREATE TABLE IF NOT EXISTS professionals (id VARCHAR(36) NOT NULL, user_id BINARY(16) NULL, store_id BINARY(16) NULL, "name" VARCHAR(100) NOT NULL, bio TEXT NULL, email VARCHAR(100) NULL, password VARCHAR(100) NULL, house_number VARCHAR(20) NULL, complement VARCHAR(100) NULL, street VARCHAR(100) NULL, neighborhood VARCHAR(100) NULL, city VARCHAR(100) NULL, "state" VARCHAR(100) NULL, country VARCHAR(100) NULL, zip_code VARCHAR(100) NULL, phone_number VARCHAR(20) NULL, phone_is_whatsapp BOOLEAN NULL, instagram VARCHAR(100) NULL, facebook VARCHAR(100) NULL, photo VARCHAR(100) NULL, work_hours VARCHAR(500) NULL, slots VARCHAR(2000) NULL);
CREATE TABLE IF NOT EXISTS services (id BINARY(16) NOT NULL, professional_id BINARY(16) NOT NULL, "name" VARCHAR(100) NOT NULL, description VARCHAR(255) NULL, price INT NOT NULL, duration_in_minutes INT NOT NULL, CONSTRAINT chk_services_signed_integer_price CHECK (price BETWEEN -2147483648 AND 2147483647), CONSTRAINT chk_services_signed_integer_duration_in_minutes CHECK (duration_in_minutes BETWEEN -2147483648 AND 2147483647));
CREATE TABLE IF NOT EXISTS slots (id BINARY(16) NOT NULL PRIMARY KEY, professional_id BINARY(16) NOT NULL, service_id BINARY(16) NULL, start_time VARCHAR(30) NOT NULL, end_time VARCHAR(30) NOT NULL, status VARCHAR(20) NOT NULL, customer_name VARCHAR(200) NULL, customer_phone VARCHAR(30) NULL);
CREATE TABLE IF NOT EXISTS customers (id BINARY(16) NOT NULL PRIMARY KEY, "name" VARCHAR(255) NOT NULL, country_code VARCHAR(5) NOT NULL, area_code VARCHAR(5) NOT NULL, phone_number VARCHAR(20) NOT NULL, is_whatsapp BOOLEAN NOT NULL, email VARCHAR(255) NULL, password VARCHAR(255) NULL);
CREATE TABLE IF NOT EXISTS schedules (id BINARY(16) NOT NULL PRIMARY KEY, professional_id BINARY(16) NOT NULL, customer_id BINARY(16) NOT NULL, observation VARCHAR(500) NOT NULL, start_time VARCHAR(30) NOT NULL, end_time VARCHAR(30) NOT NULL, "type" VARCHAR(20) NOT NULL, status VARCHAR(20) NOT NULL);
